import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, RotateCcw, BookOpen, 
  Volume2, Languages, ScrollText, 
  History, Maximize2, Layout, Share2
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_DATA, SanZiJingVerse } from '../lib/sanzijingData';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isVertical, setIsVertical] = useState(false);
  const [immersiveMode, setImmersiveMode] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [playbackRate, setPlaybackRate] = useState(0.85);
  const [activeDetail, setActiveDetail] = useState<SanZiJingVerse | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const isPlayingRef = useRef(false);
  const currentUtteranceRef = useRef<SpeechSynthesisUtterance | null>(null);

  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    isPlayingRef.current = false;
    setIsPlaying(false);
    setCurrentCharIdx(-1);
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    const verse = SAN_ZI_JING_DATA[index];
    if (!verse) return;

    const utterance = new SpeechSynthesisUtterance(verse.text);
    currentUtteranceRef.current = utterance;

    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;

    // 性能优化：限制 UI 更新频率，避免阻塞渲染线程
    let lastUpdateIdx = -1;
    utterance.onboundary = (event) => {
      if (!isPlayingRef.current) return;
      if (event.name === 'word' || event.name === 'char') {
        const textBefore = verse.text.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        const newIdx = chineseOnlyBefore.length;
        if (newIdx !== lastUpdateIdx) {
          lastUpdateIdx = newIdx;
          // 使用 requestAnimationFrame 确保 UI 更新与屏幕刷新同步
          requestAnimationFrame(() => setCurrentCharIdx(newIdx));
        }
      }
    };

    utterance.onend = () => {
      if (isPlayingRef.current) {
        if (index < SAN_ZI_JING_DATA.length - 1) {
          const next = index + 1;
          setCurrentVerseIdx(next);
          setTimeout(() => {
            if (isPlayingRef.current) playVerse(next);
          }, 400);
        } else {
          stopSpeech();
        }
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [playbackRate, stopSpeech]);

  const handleTogglePlay = () => {
    if (isPlaying) {
      stopSpeech();
    } else {
      isPlayingRef.current = true;
      setIsPlaying(true);
      playVerse(currentVerseIdx);
    }
  };

  useEffect(() => {
    return () => {
      window.speechSynthesis.cancel();
      isPlayingRef.current = false;
    };
  }, []);

  return (
    <div className={`fixed inset-0 z-50 bg-[#fdfbf7] flex flex-col font-serif text-[#2c3e50] overflow-hidden ${immersiveMode ? 'bg-[#f8f5ee]' : ''}`}>
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      {!immersiveMode && (
        <header className="h-16 md:h-20 bg-white/90 backdrop-blur-md border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-20 pt-[env(safe-area-inset-top)] shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg">
              <ScrollText size={20} />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-base font-black">三字经研习</h1>
              <div className="text-[10px] text-slate-400 uppercase tracking-widest">CHAPTER: {currentVerseIdx + 1} / {SAN_ZI_JING_DATA.length}</div>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowPinyin(!showPinyin)} 
              className={`p-2 rounded-full border transition-all ${showPinyin ? 'bg-[#c0392b] text-white border-[#c0392b]' : 'bg-white text-slate-400 border-slate-200'}`}
            >
              <Languages size={18} />
            </button>
            <button onClick={() => setImmersiveMode(true)} className="p-2 bg-[#f3efe6] rounded-full text-slate-500">
              <Maximize2 size={18} />
            </button>
            <button onClick={onClose} className="p-2 bg-red-50 text-red-400 rounded-full"><X size={20}/></button>
          </div>
        </header>
      )}

      <main 
        ref={scrollRef}
        className={`flex-1 overflow-y-auto no-scrollbar p-4 md:p-12 relative z-10`}
      >
        <div className={`max-w-3xl mx-auto space-y-4 md:space-y-8 pb-40`}>
          {SAN_ZI_JING_DATA.map((verse, vIdx) => {
            const isVerseActive = currentVerseIdx === vIdx;
            return (
              <div 
                key={verse.id}
                onClick={() => { setCurrentVerseIdx(vIdx); stopSpeech(); }}
                className={`relative p-6 md:p-10 rounded-[2rem] md:rounded-[3rem] transition-all duration-500 cursor-pointer border-2 ${isVerseActive ? 'bg-white border-[#c0392b] shadow-xl' : 'bg-transparent border-transparent opacity-60'}`}
              >
                <div className="flex flex-wrap justify-center gap-4 md:gap-8 items-center">
                  {verse.chars.map((char, charIdx) => {
                    const isCharActive = isVerseActive && currentCharIdx === charIdx;
                    return (
                      <div key={charIdx} className="flex flex-col items-center">
                        {showPinyin && (
                          <span className={`text-[9px] md:text-xs font-mono mb-1 transition-opacity ${isCharActive ? 'text-[#c0392b] opacity-100' : 'opacity-30'}`}>
                            {verse.pinyin[charIdx]}
                          </span>
                        )}
                        <span 
                          className={`text-3xl md:text-6xl font-black transition-colors ${isCharActive ? 'text-[#c0392b] scale-110' : (isVerseActive ? 'text-slate-800' : 'text-slate-300')}`}
                        >
                          {char}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </main>

      <footer className="bg-white/95 backdrop-blur-xl border-t border-[#e0d7c6] p-4 md:p-6 z-30 shrink-0">
        <div className="max-w-2xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-4">
             <button 
                onClick={handleTogglePlay}
                className="w-14 h-14 bg-[#c0392b] text-white rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
             >
                {isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} className="ml-1" fill="white" />}
             </button>
             <select 
                value={playbackRate} 
                onChange={(e) => setPlaybackRate(parseFloat(e.target.value))}
                className="bg-transparent text-xs font-bold text-[#c0392b] outline-none border border-[#c0392b]/20 rounded-lg p-1"
              >
                <option value="0.7">缓读</option>
                <option value="0.85">标准</option>
                <option value="1.1">疾读</option>
              </select>
          </div>

          <button 
            onClick={() => setActiveDetail(SAN_ZI_JING_DATA[currentVerseIdx])}
            className="flex items-center gap-2 px-6 py-3 bg-[#2c3e50] text-white rounded-full font-black text-[10px] uppercase tracking-widest hover:bg-[#c0392b] transition-all"
          >
              <BookOpen size={14} /> 译文注释
          </button>
        </div>
      </footer>

      <AnimatePresence>
        {activeDetail && (
          <motion.div 
            initial={{ y: '100%' }}
            animate={{ y: 0 }}
            exit={{ y: '100%' }}
            className="fixed inset-x-0 bottom-0 bg-white z-[110] shadow-2xl rounded-t-[2.5rem] border-t border-[#e0d7c6] max-h-[70vh] flex flex-col"
          >
            <div className="p-8 overflow-y-auto no-scrollbar">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-black text-[#2c3e50]">{activeDetail.text}</h2>
                <button onClick={() => setActiveDetail(null)} className="p-2 bg-slate-100 rounded-full"><X size={18}/></button>
              </div>
              <div className="space-y-6">
                <section>
                  <h4 className="text-[10px] font-black uppercase text-[#c0392b] mb-2">现代译文</h4>
                  <p className="text-base text-slate-600 leading-relaxed font-medium">“{activeDetail.meaning}”</p>
                </section>
                <section className="bg-[#fdfbf7] p-6 rounded-2xl border border-[#e0d7c6]">
                  <h4 className="text-xs font-black text-[#2c3e50] mb-2">{activeDetail.allusion.title}</h4>
                  <p className="text-sm text-slate-500 italic">{activeDetail.allusion.content}</p>
                </section>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        @media (max-width: 640px) {
          .writing-vertical { writing-mode: initial !important; }
        }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { X, RotateCcw, Undo2, BrainCircuit, Trophy, Settings2 } from 'lucide-react';
import { Player, Board, checkWin, getBestMove, getScoreMap } from '../lib/gobangAI';

const BOARD_SIZE = 15;
const CANVAS_SIZE = 600;
const GRID_SIZE = CANVAS_SIZE / (BOARD_SIZE + 1);

const GobangApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [board, setBoard] = useState<Board>(Array(15).fill(null).map(() => Array(15).fill(0)));
  const [currentPlayer, setCurrentPlayer] = useState<Player>(1); 
  const [gameMode, setGameMode] = useState<'PvP' | 'PvE'>('PvE');
  const [difficulty, setDifficulty] = useState<'NOVICE' | 'EXPERT' | 'MASTER'>('EXPERT');
  const [winner, setWinner] = useState<Player | 'Draw' | null>(null);
  const [history, setHistory] = useState<Board[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [lastMove, setLastMove] = useState<[number, number] | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);
  const ghostPos = useRef<{ x: number, y: number } | null>(null);
  const targetGhostPos = useRef<{ x: number, y: number } | null>(null);

  const drawStone = (ctx: CanvasRenderingContext2D, r: number, c: number, player: Player, opacity = 1) => {
    const x = (c + 1) * GRID_SIZE;
    const y = (r + 1) * GRID_SIZE;
    const radius = GRID_SIZE * 0.42;
    ctx.save();
    ctx.globalAlpha = opacity;
    const gradient = ctx.createRadialGradient(x - radius/3, y - radius/3, radius/10, x, y, radius);
    if (player === 1) { 
      gradient.addColorStop(0, '#555'); gradient.addColorStop(1, '#000'); 
    } else { 
      gradient.addColorStop(0, '#fff'); gradient.addColorStop(1, '#ccc'); 
    }
    ctx.fillStyle = gradient;
    ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.3)';
    ctx.beginPath(); ctx.arc(x, y, radius, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  };

  const render = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    if (ghostPos.current && targetGhostPos.current) {
      ghostPos.current.x += (targetGhostPos.current.x - ghostPos.current.x) * 0.2;
      ghostPos.current.y += (targetGhostPos.current.y - ghostPos.current.y) * 0.2;
    }

    ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
    ctx.fillStyle = '#d4ac6e'; ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    ctx.strokeStyle = 'rgba(0, 0, 0, 0.2)';
    ctx.lineWidth = 1;
    for (let i = 1; i <= BOARD_SIZE; i++) {
      ctx.beginPath(); ctx.moveTo(GRID_SIZE, i * GRID_SIZE); ctx.lineTo(CANVAS_SIZE - GRID_SIZE, i * GRID_SIZE); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(i * GRID_SIZE, GRID_SIZE); ctx.lineTo(i * GRID_SIZE, CANVAS_SIZE - GRID_SIZE); ctx.stroke();
    }

    board.forEach((row, r) => row.forEach((cell, c) => cell !== 0 && drawStone(ctx, r, c, cell as Player)));

    if (ghostPos.current && !winner && !isAiThinking) {
      drawStone(ctx, -1, -1, currentPlayer, 0.3); // Mock for position
      ctx.beginPath(); ctx.arc(ghostPos.current.x, ghostPos.current.y, GRID_SIZE*0.4, 0, Math.PI*2);
      ctx.fillStyle = currentPlayer === 1 ? 'rgba(0,0,0,0.2)' : 'rgba(255,255,255,0.2)'; ctx.fill();
    }

    if (lastMove) {
      const [r, c] = lastMove;
      ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.arc((c+1)*GRID_SIZE, (r+1)*GRID_SIZE, GRID_SIZE*0.45, 0, Math.PI*2); ctx.stroke();
    }

    requestRef.current = requestAnimationFrame(render);
  }, [board, currentPlayer, winner, isAiThinking, lastMove]);

  useEffect(() => {
    requestRef.current = requestAnimationFrame(render);
    return () => cancelAnimationFrame(requestRef.current);
  }, [render]);

  const handlePlaceStone = (r: number, c: number) => {
    if (winner || board[r][c] !== 0 || isAiThinking) return;
    const newBoard = board.map(row => [...row]);
    newBoard[r][c] = currentPlayer;
    setHistory(prev => [...prev, board.map(row => [...row])]);
    setBoard(newBoard);
    setLastMove([r, c]);

    if (checkWin(newBoard, r, c)) { setWinner(currentPlayer); return; }

    const nextPlayer = (currentPlayer === 1 ? 2 : 1) as Player;
    setCurrentPlayer(nextPlayer);

    if (gameMode === 'PvE' && nextPlayer === 2) {
      setIsAiThinking(true);
      setTimeout(() => {
        const [aiR, aiC] = getBestMove(newBoard, difficulty === 'NOVICE' ? 1 : 2);
        if (aiR !== -1) {
          const aiBoard = newBoard.map(row => [...row]);
          aiBoard[aiR][aiC] = 2;
          setBoard(aiBoard);
          setLastMove([aiR, aiC]);
          if (checkWin(aiBoard, aiR, aiC)) setWinner(2);
          else setCurrentPlayer(1);
        }
        setIsAiThinking(false);
      }, 600);
    }
  };

  const handleCanvasClick = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const c = Math.round(x / (rect.width / (BOARD_SIZE + 1))) - 1;
    const r = Math.round(y / (rect.height / (BOARD_SIZE + 1))) - 1;
    if (r >= 0 && r < BOARD_SIZE && c >= 0 && c < BOARD_SIZE) handlePlaceStone(r, c);
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#020617] flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-lg bg-slate-900 rounded-[2rem] border border-slate-800 p-4 md:p-8 flex flex-col gap-6 shadow-2xl">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center"><BrainCircuit className="text-white"/></div>
             <h2 className="text-white font-black tech-font">棋局对阵</h2>
          </div>
          <button onClick={onClose} className="p-2 text-slate-500 hover:text-white"><X /></button>
        </div>

        <div className="relative aspect-square bg-[#d4ac6e] rounded-xl overflow-hidden border-4 border-slate-950 shadow-inner">
          <canvas 
            ref={canvasRef} width={CANVAS_SIZE} height={CANVAS_SIZE} 
            onClick={handleCanvasClick} 
            onMouseMove={(e) => {
              const rect = canvasRef.current!.getBoundingClientRect();
              targetGhostPos.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
              if(!ghostPos.current) ghostPos.current = {...targetGhostPos.current};
            }}
            className="w-full h-full cursor-none" 
          />
          {winner && (
            <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center animate-in fade-in">
               <Trophy className="text-yellow-500 w-16 h-16 mb-4 animate-bounce" />
               <h3 className="text-white text-3xl font-black mb-6">{winner === 1 ? '你赢了！' : 'AI 胜出'}</h3>
               <button onClick={() => {setBoard(Array(15).fill(null).map(()=>Array(15).fill(0))); setWinner(null);}} className="px-8 py-3 bg-emerald-600 text-white rounded-xl font-black">再来一局</button>
            </div>
          )}
        </div>

        <div className="flex gap-4">
           <button onClick={() => { if(history.length>0) { setBoard(history[history.length-1]); setHistory(prev=>prev.slice(0,-1)); setCurrentPlayer(currentPlayer===1?2:1); }}} className="flex-1 py-4 bg-slate-800 text-slate-400 rounded-xl font-bold flex items-center justify-center gap-2"><Undo2 size={18}/>悔棋</button>
           <button onClick={() => { setBoard(Array(15).fill(null).map(()=>Array(15).fill(0))); setWinner(null); setHistory([]); }} className="flex-1 py-4 bg-slate-800 text-slate-400 rounded-xl font-bold flex items-center justify-center gap-2"><RotateCcw size={18}/>重置</button>
        </div>
      </div>
    </div>
  );
};

export default GobangApp;

