import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, RotateCcw, BookOpen, 
  Volume2, Languages, ScrollText, 
  History, Maximize2, Mic, MicOff,
  ChevronRight, Bookmark, Share2, Info,
  Sparkles, Music, Settings, Headphones
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_DATA, SanZiJingVerse } from '../lib/sanzijingData';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isShadowMode, setIsShadowMode] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [pinyinMode, setPinyinMode] = useState<'all' | 'none' | 'smart'>('all');
  const [playbackRate, setPlaybackRate] = useState(0.85);
  const [activeAllusion, setActiveAllusion] = useState<SanZiJingVerse | null>(null);
  const [learnedWords, setLearnedWords] = useState<string[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentVerseRef = useRef<HTMLDivElement>(null);
  const speechRef = useRef<SpeechSynthesisUtterance | null>(null);

  // --- 语音同步控制 ---
  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setCurrentCharIdx(-1);
  }, []);

  const playNextVerse = useCallback(() => {
    if (currentVerseIdx < SAN_ZI_JING_DATA.length - 1) {
      setCurrentVerseIdx(prev => prev + 1);
    } else {
      setIsPlaying(false);
    }
  }, [currentVerseIdx]);

  const playVerse = useCallback((index: number) => {
    window.speechSynthesis.cancel();
    const verse = SAN_ZI_JING_DATA[index];
    if (!verse) return;

    const utterance = new SpeechSynthesisUtterance(verse.text);
    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;
    speechRef.current = utterance;

    utterance.onboundary = (event) => {
      if (event.name === 'word' || event.name === 'char') {
        // 计算当前读到的字符索引（跳过标点）
        const textBefore = verse.text.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        setCurrentCharIdx(chineseOnlyBefore.length);
      }
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isShadowMode) {
        setIsUserSpeaking(true);
        // 模拟跟读时长，之后自动下一句
        setTimeout(() => {
          setIsUserSpeaking(false);
          if (isPlaying) playNextVerse();
        }, 3000);
      } else {
        setTimeout(() => {
          if (isPlaying) playNextVerse();
        }, 500);
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [playbackRate, isShadowMode, isPlaying, playNextVerse]);

  useEffect(() => {
    if (isPlaying) {
      playVerse(currentVerseIdx);
    }
    // 自动滚动到视觉中心
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [currentVerseIdx, isPlaying, playVerse]);

  const togglePlay = () => {
    if (isPlaying) stopSpeech();
    else setIsPlaying(true);
  };

  const handleCharLongPress = (char: string) => {
    if (!learnedWords.includes(char)) {
      setLearnedWords(prev => [...prev, char]);
      // 触感反馈
      if (window.navigator.vibrate) window.navigator.vibrate(50);
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#FDFBF7] flex flex-col font-serif text-[#2c3e50] overflow-hidden select-none">
      {/* 宣纸背景纹理层 */}
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none z-0 bg-gradient-to-br from-transparent via-[#c0392b]/10 to-transparent animate-pulse"></div>

      {/* 顶部导航 */}
      <header className="h-16 md:h-20 bg-white/80 backdrop-blur-xl border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-20 shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg shadow-[#c0392b]/20">
            <ScrollText size={20} />
          </div>
          <div>
            <h1 className="text-base md:text-xl font-black tracking-tight">三字经 · 精研模式</h1>
            <div className="flex items-center gap-2 mt-0.5">
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">CHAPTER {SAN_ZI_JING_DATA[currentVerseIdx].chapter}</span>
               <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
               <span className="text-[9px] font-black text-emerald-600 uppercase">进度: {((currentVerseIdx + 1) / SAN_ZI_JING_DATA.length * 100).toFixed(0)}%</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
           <button 
             onClick={() => setPinyinMode(p => p === 'all' ? 'none' : p === 'none' ? 'smart' : 'all')}
             className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white border border-[#e0d7c6] rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-[#f3efe6] transition-all"
           >
             <Languages size={14} /> 拼音: {pinyinMode === 'all' ? '全显' : pinyinMode === 'none' ? '隐藏' : '生僻'}
           </button>
           <button onClick={onClose} className="p-2 md:p-3 bg-[#f3efe6] text-slate-400 hover:text-red-500 rounded-full transition-all active:scale-95">
             <X size={20} />
           </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:grid lg:grid-cols-2 overflow-hidden relative z-10">
        {/* 左侧文字滚动区 */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto no-scrollbar p-6 md:p-12 lg:p-20 space-y-12 md:space-y-24 scroll-smooth pb-40"
        >
          {SAN_ZI_JING_DATA.map((verse, vIdx) => (
            <div 
              key={verse.id}
              ref={currentVerseIdx === vIdx ? currentVerseRef : null}
              onClick={() => { setCurrentVerseIdx(vIdx); stopSpeech(); }}
              className={`relative transition-all duration-700 cursor-pointer ${currentVerseIdx === vIdx ? 'scale-105 opacity-100' : 'opacity-30 blur-[0.5px] grayscale'}`}
            >
              <div className="flex flex-wrap justify-center gap-4 md:gap-10">
                {verse.chars.map((char, cIdx) => {
                  const isActive = currentVerseIdx === vIdx && currentCharIdx === cIdx;
                  const showPinyin = pinyinMode === 'all' || (pinyinMode === 'smart' && verse.isHard);

                  return (
                    <motion.div 
                      key={cIdx} 
                      onContextMenu={(e) => { e.preventDefault(); handleCharLongPress(char); }}
                      className="flex flex-col items-center group relative"
                      animate={isActive ? { y: -5, scale: 1.15 } : { y: 0, scale: 1 }}
                    >
                      <AnimatePresence>
                        {showPinyin && (
                          <motion.span 
                            initial={{ opacity: 0, y: 5 }}
                            animate={{ opacity: 1, y: 0 }}
                            className={`text-[10px] md:text-xs font-mono mb-2 transition-colors ${isActive ? 'text-[#c0392b] font-black' : 'text-slate-400'}`}
                          >
                            {verse.pinyin[cIdx]}
                          </motion.span>
                        )}
                      </AnimatePresence>
                      <span className={`
                        text-4xl md:text-7xl lg:text-8xl font-black transition-all duration-500 leading-none
                        ${isActive ? 'text-[#1a1a1a] drop-shadow-xl' : 'text-slate-300'}
                        ${learnedWords.includes(char) ? 'underline decoration-[#c0392b] decoration-wavy' : ''}
                      `}>
                        {char}
                      </span>
                      {isActive && (
                        <motion.div 
                          layoutId="ink-dot"
                          className="absolute -bottom-4 w-2 h-2 bg-[#c0392b] rounded-full blur-[1px]"
                        />
                      )}
                    </motion.div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* 右侧解析面板 (仅桌面端常驻，移动端点击弹出) */}
        <div className="hidden lg:flex flex-col bg-white/30 backdrop-blur-sm border-l border-[#e0d7c6] p-12 overflow-y-auto no-scrollbar">
           <AnimatePresence mode="wait">
             <motion.section 
               key={currentVerseIdx}
               initial={{ opacity: 0, x: 20 }}
               animate={{ opacity: 1, x: 0 }}
               exit={{ opacity: 0, x: -20 }}
               className="space-y-12"
             >
                <div>
                   <h3 className="text-[10px] font-black text-[#c0392b] uppercase tracking-[0.4em] mb-4 italic">现代白话 / TRANSLATION</h3>
                   <p className="text-2xl text-slate-600 leading-relaxed font-bold italic">
                     “{SAN_ZI_JING_DATA[currentVerseIdx].meaning}”
                   </p>
                </div>

                <div className="bg-white p-8 rounded-[3rem] border border-[#e0d7c6] shadow-sm relative overflow-hidden group">
                   <div className="absolute top-0 right-0 p-6 opacity-[0.04] group-hover:rotate-12 transition-transform duration-700"><Sparkles size={100}/></div>
                   <div className="flex items-center gap-3 mb-6">
                      <BookOpen className="text-[#c0392b]" size={18} />
                      <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">典故背景: {SAN_ZI_JING_DATA[currentVerseIdx].allusion.title}</h4>
                   </div>
                   <p className="text-sm text-slate-500 leading-relaxed mb-6 font-medium italic">
                     {SAN_ZI_JING_DATA[currentVerseIdx].allusion.content}
                   </p>
                   <div className="text-[9px] text-[#c0392b] font-black uppercase tracking-[0.2em] opacity-40">
                     出处: {SAN_ZI_JING_DATA[currentVerseIdx].allusion.source}
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-[#f3efe6] p-6 rounded-2xl border border-[#e0d7c6]/50">
                    <div className="text-[9px] font-black text-slate-400 mb-2">章节关键词</div>
                    <div className="flex flex-wrap gap-2">
                       {SAN_ZI_JING_DATA[currentVerseIdx].chars.slice(0, 3).map(c => (
                         <span key={c} className="px-2 py-1 bg-white rounded text-[10px] font-bold">{c}</span>
                       ))}
                    </div>
                  </div>
                  <button className="flex flex-col items-center justify-center bg-[#c0392b] text-white rounded-2xl shadow-lg hover:bg-[#a93226] transition-all group">
                     <Bookmark size={20} className="mb-2 group-hover:scale-110 transition-transform" />
                     <span className="text-[10px] font-black">收藏金句</span>
                  </button>
                </div>
             </motion.section>
           </AnimatePresence>
        </div>
      </main>

      {/* 底部控制中心 */}
      <footer className="h-24 md:h-28 bg-white/95 backdrop-blur-2xl border-t border-[#e0d7c6] px-4 md:px-12 z-30 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4 md:gap-8">
           <button 
             onClick={togglePlay}
             className={`w-14 h-14 md:w-16 md:h-16 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isPlaying ? 'bg-slate-900 text-white' : 'bg-[#c0392b] text-white'}`}
           >
             {isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} className="ml-1" fill="white" />}
           </button>

           <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">播放倍速</span>
              <select 
                value={playbackRate} 
                onChange={(e) => setPlaybackRate(parseFloat(e.target.value))}
                className="bg-transparent text-xs font-bold text-[#c0392b] outline-none"
              >
                <option value="0.7">0.7x 缓读</option>
                <option value="0.85">0.85x 标准</option>
                <option value="1.0">1.0x 疾读</option>
              </select>
           </div>
        </div>

        {/* 动态音量/跟读状态指示器 */}
        <div className="hidden sm:flex items-center gap-6 px-10 py-3 bg-[#f3efe6] rounded-full border border-[#e0d7c6]">
           <button 
             onClick={() => setIsShadowMode(!isShadowMode)}
             className={`flex items-center gap-2 transition-all ${isShadowMode ? 'text-[#c0392b]' : 'text-slate-400'}`}
           >
              {isShadowMode ? <Mic size={18} className="animate-pulse" /> : <MicOff size={18} />}
              <span className="text-[10px] font-black uppercase tracking-widest">{isShadowMode ? '跟读模式: ON' : '跟读模式: OFF'}</span>
           </button>
           <div className="w-px h-4 bg-[#e0d7c6]"></div>
           <div className="flex gap-0.5">
              {[...Array(8)].map((_, i) => (
                <div key={i} className={`w-0.5 h-3 rounded-full transition-all ${isUserSpeaking ? 'bg-[#c0392b] animate-bounce' : 'bg-slate-300'}`} style={{ animationDelay: `${i * 0.1}s` }}></div>
              ))}
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
            onClick={() => setActiveAllusion(SAN_ZI_JING_DATA[currentVerseIdx])}
            className="lg:hidden p-3 bg-slate-900 text-white rounded-full shadow-lg"
           >
             <BookOpen size={20} />
           </button>
           <button className="p-3 bg-white border border-[#e0d7c6] text-slate-400 rounded-full hover:text-[#c0392b] transition-all">
             <Share2 size={20} />
           </button>
        </div>
      </footer>

      {/* 典故详情抽屉 (移动端适配) */}
      <AnimatePresence>
        {activeAllusion && (
          <>
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setActiveAllusion(null)}
              className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100]"
            />
            <motion.div 
              initial={{ y: '100%' }}
              animate={{ y: 0 }}
              exit={{ y: '100%' }}
              className="fixed inset-x-0 bottom-0 bg-[#FDFBF7] z-[110] rounded-t-[3rem] shadow-2xl border-t border-[#e0d7c6] max-h-[85vh] flex flex-col"
            >
              <div className="p-8 md:p-12 overflow-y-auto no-scrollbar">
                 <div className="flex justify-between items-center mb-8">
                    <h2 className="text-3xl font-black text-[#2c3e50] italic">{activeAllusion.text}</h2>
                    <button onClick={() => setActiveAllusion(null)} className="p-2 bg-[#f3efe6] rounded-full"><X size={20}/></button>
                 </div>

                 <div className="space-y-10 pb-10">
                    <section>
                      <h4 className="text-[10px] font-black uppercase text-[#c0392b] tracking-widest mb-4">逐字精译</h4>
                      <p className="text-xl text-slate-600 leading-relaxed font-bold italic">“{activeAllusion.meaning}”</p>
                    </section>

                    <section className="bg-white p-8 rounded-[2rem] border border-[#e0d7c6]">
                       <h4 className="text-xs font-black text-slate-800 mb-4">典故: {activeAllusion.allusion.title}</h4>
                       <p className="text-sm text-slate-500 leading-relaxed font-medium italic">
                         {activeAllusion.allusion.content}
                       </p>
                    </section>
                 </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @media (max-width: 640px) {
          .writing-vertical {
            writing-mode: initial !important;
          }
        }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, BookOpen, 
  Languages, ScrollText, 
  Maximize2, Mic, MicOff,
  ChevronRight, Bookmark, Share2,
  Sparkles
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_DATA, SanZiJingVerse } from '../lib/sanzijingData';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isShadowMode, setIsShadowMode] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [pinyinMode, setPinyinMode] = useState<'all' | 'none' | 'smart'>('all');
  const [playbackRate, setPlaybackRate] = useState(0.85);
  const [activeAllusion, setActiveAllusion] = useState<SanZiJingVerse | null>(null);
  const [learnedWords, setLearnedWords] = useState<string[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentVerseRef = useRef<HTMLDivElement>(null);
  const isComponentMounted = useRef(true);
  const lastIndexRef = useRef(-1); // 性能关键：记录上次更新的索引

  // --- 彻底清理语音系统 ---
  const stopSpeech = useCallback(() => {
    if (window.speechSynthesis) {
      window.speechSynthesis.cancel();
    }
    setIsPlaying(false);
    setCurrentCharIdx(-1);
    lastIndexRef.current = -1;
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!window.speechSynthesis) return;

    window.speechSynthesis.cancel(); // 启动前强制重置
    const verse = SAN_ZI_JING_DATA[index];
    if (!verse) return;

    const utterance = new SpeechSynthesisUtterance(verse.text);
    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;

    // 性能优化：使用 ref 拦截无效的重复渲染
    utterance.onboundary = (event) => {
      if (!isComponentMounted.current) return;
      if (event.name === 'word' || event.name === 'char') {
        const textBefore = verse.text.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        const newIdx = chineseOnlyBefore.length;

        if (newIdx !== lastIndexRef.current) {
          lastIndexRef.current = newIdx;
          // 使用 requestAnimationFrame 确保同步
          requestAnimationFrame(() => {
            setCurrentCharIdx(newIdx);
          });
        }
      }
    };

    utterance.onend = () => {
      if (!isComponentMounted.current) return;
      requestAnimationFrame(() => setCurrentCharIdx(-1));

      if (isShadowMode) {
        setIsUserSpeaking(true);
        setTimeout(() => {
          if (isComponentMounted.current && isPlaying) {
            setIsUserSpeaking(false);
            if (index < SAN_ZI_JING_DATA.length - 1) {
              setCurrentVerseIdx(index + 1);
            } else {
              setIsPlaying(false);
            }
          }
        }, 2500);
      } else if (isPlaying) {
        setTimeout(() => {
          if (isComponentMounted.current && isPlaying) {
            if (index < SAN_ZI_JING_DATA.length - 1) {
              setCurrentVerseIdx(index + 1);
            } else {
              setIsPlaying(false);
            }
          }
        }, 400);
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [playbackRate, isShadowMode, isPlaying]);

  // 管理生命周期
  useEffect(() => {
    isComponentMounted.current = true;
    return () => {
      isComponentMounted.current = false;
      window.speechSynthesis.cancel();
    };
  }, []);

  useEffect(() => {
    if (isPlaying) {
      playVerse(currentVerseIdx);
    }
    // 平滑滚动优化：仅在当前行变化时滚动
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [currentVerseIdx, isPlaying, playVerse]);

  const togglePlay = () => {
    if (isPlaying) stopSpeech();
    else setIsPlaying(true);
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#FDFBF7] flex flex-col font-serif text-[#2c3e50] overflow-hidden select-none">
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      {/* 顶部导航 */}
      <header className="h-16 md:h-20 bg-white/90 backdrop-blur-xl border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-20 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg">
            <ScrollText size={20} />
          </div>
          <div>
            <h1 className="text-base md:text-xl font-black">三字经研习</h1>
            <div className="flex items-center gap-2">
               <span className="text-[9px] font-black text-slate-400 uppercase">CHAPTER {SAN_ZI_JING_DATA[currentVerseIdx].chapter}</span>
               <span className="text-[9px] font-black text-emerald-600 uppercase">进度: {((currentVerseIdx + 1) / SAN_ZI_JING_DATA.length * 100).toFixed(0)}%</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => setPinyinMode(p => p === 'all' ? 'none' : p === 'none' ? 'smart' : 'all')}
             className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white border border-[#e0d7c6] rounded-full text-[10px] font-black uppercase hover:bg-[#f3efe6]"
           >
             <Languages size={14} /> 拼音
           </button>
           <button onClick={onClose} className="p-2 bg-[#f3efe6] text-slate-400 hover:text-red-500 rounded-full transition-all">
             <X size={20} />
           </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:grid lg:grid-cols-2 overflow-hidden relative z-10">
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto no-scrollbar p-6 md:p-12 space-y-12 md:space-y-24 scroll-smooth pb-40"
        >
          {SAN_ZI_JING_DATA.map((verse, vIdx) => {
            const isLineActive = currentVerseIdx === vIdx;
            return (
              <div 
                key={verse.id}
                ref={isLineActive ? currentVerseRef : null}
                onClick={() => { if(!isPlaying) setCurrentVerseIdx(vIdx); else { stopSpeech(); setCurrentVerseIdx(vIdx); } }}
                className={`relative transition-all duration-500 cursor-pointer ${isLineActive ? 'opacity-100' : 'opacity-30 grayscale'}`}
              >
                <div className="flex flex-wrap justify-center gap-4 md:gap-8">
                  {verse.chars.map((char, cIdx) => {
                    const isCharActive = isLineActive && currentCharIdx === cIdx;
                    const showPinyin = pinyinMode === 'all' || (pinyinMode === 'smart' && verse.isHard);

                    return (
                      <div key={cIdx} className="flex flex-col items-center min-w-[3rem] md:min-w-[5rem]">
                        <div className="h-4 md:h-6 flex items-end justify-center mb-1">
                          <AnimatePresence>
                            {showPinyin && (
                              <motion.span 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                className={`text-[10px] md:text-sm font-mono transition-colors ${isCharActive ? 'text-[#c0392b] font-black' : 'text-slate-400'}`}
                              >
                                {verse.pinyin[cIdx]}
                              </motion.span>
                            )}
                          </AnimatePresence>
                        </div>
                        <span className={`
                          text-4xl md:text-7xl font-black transition-all duration-300
                          ${isCharActive ? 'text-[#c0392b] scale-110' : 'text-slate-800'}
                          ${learnedWords.includes(char) ? 'border-b-2 border-[#c0392b]' : ''}
                        `}>
                          {char}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>

        {/* 桌面端解析面板 */}
