import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, BookOpen, 
  Languages, ScrollText, 
  Maximize2, Mic, MicOff,
  ChevronRight, Bookmark, Share2,
  Sparkles, CloudSync, Database, RefreshCw, AlertCircle
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_FULL_DATA, SanZiJingVerse } from '../lib/sanzijingData';
import sql from '../lib/neon';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>(SAN_ZI_JING_FULL_DATA);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [pinyinMode, setPinyinMode] = useState<'all' | 'none'>('all');
  const [playbackRate, setPlaybackRate] = useState(0.85);
  const [activeAllusion, setActiveAllusion] = useState<SanZiJingVerse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'LOCAL' | 'CLOUD' | 'SYNCING'>('LOCAL');

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentVerseRef = useRef<HTMLDivElement>(null);
  const isComponentMounted = useRef(true);

  // 性能加固：防止 React 在高频语音事件中死锁
  const pendingCharIdx = useRef(-1);
  const animationFrameRef = useRef<number | null>(null);

  // --- 数据库初始化与同步 ---
  const initDatabase = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    setSyncStatus('SYNCING');
    try {
      // 1. 尝试创建表
      await sql`
        CREATE TABLE IF NOT EXISTS sanzijing_verses (
          id INT PRIMARY KEY,
          chapter INT,
          text TEXT,
          chars TEXT[],
          pinyin TEXT[],
          meaning TEXT,
          allusion_title TEXT,
          allusion_content TEXT
        )
      `;

      // 2. 检查是否有数据
      const countResult = await sql`SELECT count(*) FROM sanzijing_verses`;
      const count = parseInt(countResult[0].count);

      if (count === 0) {
        console.log("Initializing cloud classic data...");
        // 批量插入
        for (const v of SAN_ZI_JING_FULL_DATA) {
          await sql`
            INSERT INTO sanzijing_verses (id, chapter, text, chars, pinyin, meaning, allusion_title, allusion_content)
            VALUES (${v.id}, ${v.chapter}, ${v.text}, ${v.chars}, ${v.pinyin}, ${v.meaning}, ${v.allusion.title}, ${v.allusion.content})
            ON CONFLICT (id) DO NOTHING
          `;
        }
      }

      // 3. 从云端读取最新全量数据
      const cloudData = await sql`SELECT * FROM sanzijing_verses ORDER BY id ASC`;
      const formatted = cloudData.map(d => ({
        id: d.id,
        chapter: d.chapter,
        text: d.text,
        chars: d.chars,
        pinyin: d.pinyin,
        meaning: d.meaning,
        allusion: { title: d.allusion_title, content: d.allusion_content }
      }));

      setVerses(formatted);
      setSyncStatus('CLOUD');
    } catch (e) {
      console.error("Cloud Sync Failed:", e);
      setSyncStatus('LOCAL');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    initDatabase();
    return () => {
      isComponentMounted.current = false;
      window.speechSynthesis.cancel();
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [initDatabase]);

  // --- 防崩溃渲染逻辑 ---
  const syncUIState = useCallback(() => {
    if (pendingCharIdx.current !== currentCharIdx) {
      setCurrentCharIdx(pendingCharIdx.current);
    }
    if (isPlaying && isComponentMounted.current) {
      animationFrameRef.current = requestAnimationFrame(syncUIState);
    }
  }, [currentCharIdx, isPlaying]);

  useEffect(() => {
    if (isPlaying) {
      animationFrameRef.current = requestAnimationFrame(syncUIState);
    } else {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }
  }, [isPlaying, syncUIState]);

  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setCurrentCharIdx(-1);
    pendingCharIdx.current = -1;
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();

    const verse = verses[index];
    if (!verse) return;

    const utterance = new SpeechSynthesisUtterance(verse.text);
    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;

    utterance.onboundary = (event) => {
      if (!isComponentMounted.current) return;
      if (event.name === 'word' || event.name === 'char') {
        const textBefore = verse.text.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        pendingCharIdx.current = chineseOnlyBefore.length;
      }
    };

    utterance.onend = () => {
      if (!isComponentMounted.current) return;
      pendingCharIdx.current = -1;
      if (isPlaying) {
        setTimeout(() => {
          if (isComponentMounted.current && isPlaying) {
            if (index < verses.length - 1) {
              setCurrentVerseIdx(index + 1);
            } else {
              setIsPlaying(false);
            }
          }
        }, 500);
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [playbackRate, isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) {
      playVerse(currentVerseIdx);
    }
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [currentVerseIdx, isPlaying, playVerse]);

  return (
    <div className="fixed inset-0 z-50 bg-[#FDFBF7] flex flex-col font-serif text-[#2c3e50] overflow-hidden select-none">
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      <header className="h-16 md:h-24 bg-white/90 backdrop-blur-xl border-b border-[#e0d7c6] flex items-center justify-between px-6 md:px-10 z-20 shrink-0 pt-[env(safe-area-inset-top)]">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-[#c0392b] text-white rounded-2xl flex items-center justify-center shadow-lg shadow-[#c0392b]/20">
            <ScrollText size={24} />
          </div>
          <div>
            <h1 className="text-lg md:text-2xl font-black tracking-tight">三字经 · 全文研习</h1>
            <div className="flex items-center gap-2 mt-1">
               <span className={`flex items-center gap-1 text-[9px] font-black uppercase px-2 py-0.5 rounded-full border ${syncStatus === 'CLOUD' ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-slate-100 text-slate-400 border-slate-200'}`}>
                 {syncStatus === 'SYNCING' ? <RefreshCw size={8} className="animate-spin" /> : <Database size={8} />}
                 {syncStatus} STORAGE
               </span>
               <span className="text-[9px] font-black text-[#c0392b] uppercase tracking-widest bg-[#c0392b]/5 px-2 py-0.5 rounded-full">
                 进度: {((currentVerseIdx + 1) / verses.length * 100).toFixed(0)}%
               </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
           <button 
             onClick={() => setPinyinMode(p => p === 'all' ? 'none' : 'all')}
             className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white border border-[#e0d7c6] rounded-xl text-[10px] font-black uppercase shadow-sm hover:bg-[#f3efe6]"
           >
             <Languages size={14} /> 拼音
           </button>
           <button onClick={onClose} className="p-3 bg-[#f3efe6] text-slate-400 hover:text-red-500 rounded-full transition-all active:scale-90">
             <X size={20} />
           </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:grid lg:grid-cols-2 overflow-hidden relative z-10">
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto no-scrollbar p-6 md:p-16 space-y-16 md:space-y-32 scroll-smooth pb-48"
        >
          {isLoading ? (
            <div className="h-full flex flex-col items-center justify-center opacity-30">
               <RefreshCw className="animate-spin mb-4" size={48} />
               <p className="text-xs font-black tracking-[0.5em] uppercase">初始化云端卷轴...</p>
            </div>
          ) : (
            verses.map((verse, vIdx) => {
              const isLineActive = currentVerseIdx === vIdx;
              return (
                <div 
                  key={verse.id}
                  ref={isLineActive ? currentVerseRef : null}
                  onClick={() => { stopSpeech(); setCurrentVerseIdx(vIdx); }}
                  className={`relative transition-all duration-700 cursor-pointer ${isLineActive ? 'opacity-100 scale-110 translate-x-2' : 'opacity-20 blur-[1px] grayscale'}`}
                >
                  <div className="flex flex-wrap justify-center gap-4 md:gap-12">
                    {verse.chars.map((char, cIdx) => {
                      const isCharActive = isLineActive && currentCharIdx === cIdx;
                      return (
                        <div key={cIdx} className="flex flex-col items-center min-w-[3.5rem] md:min-w-[6rem]">
                          <div className="h-6 md:h-8 flex items-end justify-center mb-2">
                            {pinyinMode === 'all' && (
                              <span className={`text-[10px] md:text-base font-mono transition-colors duration-300 ${isCharActive ? 'text-[#c0392b] font-black' : 'text-slate-400'}`}>
                                {verse.pinyin[cIdx]}
                              </span>
                            )}
                          </div>
                          <span className={`
                            text-5xl md:text-8xl font-black transition-all duration-500
                            ${isCharActive ? 'text-[#1a1a1a] drop-shadow-xl' : 'text-slate-300'}
                          `}>
                            {char}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* 桌面端解析面板 */}
        <div className="hidden lg:flex flex-col bg-white/40 backdrop-blur-sm border-l border-[#e0d7c6] p-16 overflow-y-auto no-scrollbar relative">
           <AnimatePresence mode="wait">
             <motion.section 
               key={currentVerseIdx}
               initial={{ opacity: 0, x: 30 }}
               animate={{ opacity: 1, x: 0 }}
               exit={{ opacity: 0, x: -30 }}
               className="space-y-16"
             >
                <div>
                   <h3 className="text-[10px] font-black text-[#c0392b] uppercase tracking-[0.6em] mb-6 italic border-b border-[#c0392b]/10 pb-2 flex items-center gap-2">
