                        <BookOpen size={20} />
                      </div>
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">典故背景: {verses[currentVerseIdx].allusion.title}</h4>
                   </div>
                   <p className="text-base text-slate-500 leading-relaxed italic font-medium">
                     {verses[currentVerseIdx].allusion.content}
                   </p>
                </div>
             </motion.section>
           </AnimatePresence>
        </div>
      </main>

      <footer className="h-28 bg-white/95 backdrop-blur-2xl border-t border-[#e0d7c6] px-6 md:px-16 z-30 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-10">
           <button 
             onClick={() => isPlaying ? stopSpeech() : setIsPlaying(true)}
             className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isPlaying ? 'bg-slate-900 text-white' : 'bg-[#c0392b] text-white shadow-[#c0392b]/30'}`}
           >
             {isPlaying ? <Pause size={28} fill="white" /> : <Play size={28} className="ml-1" fill="white" />}
           </button>

           <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">语速调节</span>
              <div className="flex gap-4">
                 {[0.7, 0.85, 1.1].map(r => (
                   <button 
                    key={r} onClick={() => setPlaybackRate(r)}
                    className={`px-3 py-1 rounded-lg text-[10px] font-black border transition-all ${playbackRate === r ? 'bg-[#c0392b] text-white border-[#c0392b]' : 'bg-transparent text-slate-400 border-slate-200 hover:border-[#c0392b]'}`}
                   >
                     {r === 0.7 ? '缓' : r === 0.85 ? '准' : '疾'}
                   </button>
                 ))}
              </div>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <button 
             onClick={() => setActiveAllusion(verses[currentVerseIdx])}
             className="lg:hidden flex items-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs shadow-lg"
           >
             <BookOpen size={16} /> 查看译文
           </button>
           <button className="p-4 bg-white border border-[#e0d7c6] text-slate-400 rounded-2xl hover:text-[#c0392b] transition-all">
             <Share2 size={20} />
           </button>
        </div>
      </footer>

      {/* 移动端详情抽屉 */}
      <AnimatePresence>
        {activeAllusion && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setActiveAllusion(null)} className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[100]" />
            <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} className="fixed inset-x-0 bottom-0 bg-[#FDFBF7] z-[110] rounded-t-[4rem] shadow-2xl border-t border-[#e0d7c6] max-h-[85vh] overflow-y-auto p-12" >
