          chars TEXT[],
          pinyin TEXT[],
          meaning TEXT,
          allusion_title TEXT,
          allusion_content TEXT
        )
      `;

      const countResult = await sql`SELECT count(*) FROM sanzijing_verses`;
      const cloudCount = parseInt(countResult[0].count);

      // 如果云端为空，或者本地代码数据量更大（说明有更新），或者用户强制刷新
      if (cloudCount === 0 || SAN_ZI_JING_FULL_DATA.length > cloudCount || force) {
        console.log("Updating cloud storage with latest full version...");
        // 清理旧数据以防冲突（如果是强制刷新）
        if (force) await sql`DELETE FROM sanzijing_verses`;

        for (const v of SAN_ZI_JING_FULL_DATA) {
          await sql`
            INSERT INTO sanzijing_verses (id, chapter, text, chars, pinyin, meaning, allusion_title, allusion_content)
            VALUES (${v.id}, ${v.chapter}, ${v.text}, ${v.chars}, ${v.pinyin}, ${v.meaning}, ${v.allusion.title}, ${v.allusion.content})
            ON CONFLICT (id) DO UPDATE SET
              text = EXCLUDED.text,
              chars = EXCLUDED.chars,
              pinyin = EXCLUDED.pinyin,
              meaning = EXCLUDED.meaning,
              allusion_title = EXCLUDED.allusion_title,
              allusion_content = EXCLUDED.allusion_content
          `;
        }
      }

      const cloudData = await sql`SELECT * FROM sanzijing_verses ORDER BY id ASC`;
      const formatted = cloudData.map(d => ({
        id: d.id, chapter: d.chapter, text: d.text, chars: d.chars, pinyin: d.pinyin, meaning: d.meaning,
        allusion: { title: d.allusion_title, content: d.allusion_content }
      }));

      setVerses(formatted);
      setSyncStatus('CLOUD');
    } catch (e) {
      console.error("Database Sync Error:", e);
      setSyncStatus('LOCAL');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    syncDatabase();
    return () => {
      isComponentMounted.current = false;
      window.speechSynthesis.cancel();
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [syncDatabase]);

  // --- 高性能渲染调度 ---
  const syncUIState = useCallback(() => {
    if (pendingCharIdx.current !== currentCharIdx) {
      setCurrentCharIdx(pendingCharIdx.current);
    }
    if (isPlaying && isComponentMounted.current) {
      animationFrameRef.current = requestAnimationFrame(syncUIState);
    }
  }, [currentCharIdx, isPlaying]);

  useEffect(() => {
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(syncUIState);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
  }, [isPlaying, syncUIState]);

  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setCurrentCharIdx(-1);
    pendingCharIdx.current = -1;
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!window.speechSynthesis || !verses[index]) return;
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(verses[index].text);
    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;

    utterance.onboundary = (event) => {
      if (!isComponentMounted.current) return;
      if (event.name === 'word' || event.name === 'char') {
        const textBefore = verses[index].text.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        pendingCharIdx.current = chineseOnlyBefore.length;
      }
    };

    utterance.onend = () => {
      if (!isComponentMounted.current) return;
      pendingCharIdx.current = -1;
      if (isPlaying) {
        setTimeout(() => {
          if (isComponentMounted.current && isPlaying) {
            if (index < verses.length - 1) setCurrentVerseIdx(index + 1);
            else setIsPlaying(false);
          }
        }, 600);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [playbackRate, isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerse(currentVerseIdx);
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [currentVerseIdx, isPlaying, playVerse]);

  return (
    <div className="fixed inset-0 z-50 bg-[#FDFBF7] flex flex-col font-serif text-[#2c3e50] overflow-hidden select-none">
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      <header className="h-16 md:h-24 bg-white/90 backdrop-blur-xl border-b border-[#e0d7c6] flex items-center justify-between px-6 md:px-10 z-20 shrink-0 pt-[env(safe-area-inset-top)]">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-[#c0392b] text-white rounded-2xl flex items-center justify-center shadow-lg shadow-[#c0392b]/20">
            <ScrollText size={24} />
          </div>
          <div>
            <h1 className="text-lg md:text-2xl font-black tracking-tight">三字经 · 全文研习</h1>
            <div className="flex items-center gap-2 mt-1">
               <button 
                 onClick={() => syncDatabase(true)}
                 className={`flex items-center gap-1 text-[9px] font-black uppercase px-2 py-0.5 rounded-full border transition-all ${syncStatus === 'CLOUD' ? 'bg-emerald-50 text-emerald-600 border-emerald-200 hover:bg-emerald-100' : 'bg-slate-100 text-slate-400 border-slate-200'}`}
                 title="点击重刷云端数据"
               >
                 {syncStatus === 'SYNCING' ? <RefreshCw size={8} className="animate-spin" /> : <Database size={8} />}
                 {syncStatus} SYNC
               </button>
               <span className="text-[9px] font-black text-[#c0392b] uppercase tracking-widest bg-[#c0392b]/5 px-2 py-0.5 rounded-full">
                 进度: {((currentVerseIdx + 1) / verses.length * 100).toFixed(0)}%
               </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
           <button onClick={() => setPinyinMode(p => p === 'all' ? 'none' : 'all')} className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white border border-[#e0d7c6] rounded-xl text-[10px] font-black hover:bg-[#f3efe6]">
             <Languages size={14} /> 拼音
           </button>
           <button onClick={onClose} className="p-3 bg-[#f3efe6] text-slate-400 hover:text-red-500 rounded-full transition-all active:scale-90"><X size={20} /></button>
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:grid lg:grid-cols-2 overflow-hidden relative z-10">
        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 md:p-16 space-y-16 md:space-y-32 scroll-smooth pb-48">
          {isLoading ? (
            <div className="h-full flex flex-col items-center justify-center opacity-30">
               <RefreshCw className="animate-spin mb-4" size={48} />
               <p className="text-xs font-black tracking-[0.5em] uppercase">同步全量经文...</p>
            </div>
          ) : (
            verses.map((verse, vIdx) => {
              const isLineActive = currentVerseIdx === vIdx;
              return (
                <div key={verse.id} ref={isLineActive ? currentVerseRef : null} onClick={() => { stopSpeech(); setCurrentVerseIdx(vIdx); }} className={`relative transition-all duration-700 cursor-pointer ${isLineActive ? 'opacity-100 scale-110 translate-x-2' : 'opacity-20 blur-[1px] grayscale'}`}>
                  <div className="flex flex-wrap justify-center gap-4 md:gap-12">
                    {verse.chars.map((char, cIdx) => (
                      <div key={cIdx} className="flex flex-col items-center min-w-[3.5rem] md:min-w-[6rem]">
                        <div className="h-6 md:h-8 flex items-end justify-center mb-2">
                          {pinyinMode === 'all' && (
                            <span className={`text-[10px] md:text-base font-mono transition-colors duration-300 ${isLineActive && currentCharIdx === cIdx ? 'text-[#c0392b] font-black' : 'text-slate-400'}`}>{verse.pinyin[cIdx]}</span>
                          )}
                        </div>
                        <span className={`text-5xl md:text-8xl font-black transition-all duration-500 ${isLineActive && currentCharIdx === cIdx ? 'text-[#1a1a1a] drop-shadow-xl scale-110' : isLineActive ? 'text-slate-600' : 'text-slate-300'}`}>{char}</span>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })
          )}
        </div>

        <div className="hidden lg:flex flex-col bg-white/40 backdrop-blur-sm border-l border-[#e0d7c6] p-16 overflow-y-auto no-scrollbar relative">
           <AnimatePresence mode="wait">
             <motion.section key={currentVerseIdx} initial={{ opacity: 0, x: 30 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -30 }} className="space-y-16">
                <div>
                   <h3 className="text-[10px] font-black text-[#c0392b] uppercase tracking-[0.6em] mb-6 italic border-b border-[#c0392b]/10 pb-2 flex items-center gap-2"><Sparkles size={12}/> 现代通译</h3>
                   <p className="text-3xl text-slate-700 leading-relaxed font-bold italic">“{verses[currentVerseIdx].meaning}”</p>
                </div>
                <div className="bg-white p-12 rounded-[4rem] border border-[#e0d7c6] shadow-xl relative overflow-hidden group">
                   <div className="absolute -top-10 -right-10 p-6 opacity-[0.03] group-hover:rotate-12 transition-transform duration-700"><ScrollText size={160}/></div>
                   <div className="flex items-center gap-4 mb-8">
                      <div className="w-10 h-10 bg-[#c0392b]/10 rounded-xl flex items-center justify-center text-[#c0392b]"><BookOpen size={20} /></div>
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">典故背景: {verses[currentVerseIdx].allusion.title}</h4>
                   </div>
                   <p className="text-base text-slate-500 leading-relaxed italic font-medium">{verses[currentVerseIdx].allusion.content}</p>
                </div>
             </motion.section>
           </AnimatePresence>
        </div>
      </main>

      <footer className="h-28 bg-white/95 backdrop-blur-2xl border-t border-[#e0d7c6] px-6 md:px-16 z-30 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-10">
           <button onClick={() => isPlaying ? stopSpeech() : setIsPlaying(true)} className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${isPlaying ? 'bg-slate-900 text-white' : 'bg-[#c0392b] text-white'}`}>
             {isPlaying ? <Pause size={28} fill="white" /> : <Play size={28} className="ml-1" fill="white" />}
           </button>
           <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">语速调节</span>
              <div className="flex gap-4">
                 {[0.7, 0.85, 1.1].map(r => (
                   <button key={r} onClick={() => setPlaybackRate(r)} className={`px-3 py-1 rounded-lg text-[10px] font-black border transition-all ${playbackRate === r ? 'bg-[#c0392b] text-white border-[#c0392b]' : 'bg-transparent text-slate-400 border-slate-200'}`}>{r === 0.7 ? '缓' : r === 0.85 ? '准' : '疾'}</button>
                 ))}
              </div>
           </div>
        </div>
        <div className="flex items-center gap-4">
           <button onClick={() => setActiveAllusion(verses[currentVerseIdx])} className="lg:hidden flex items-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs shadow-lg"><BookOpen size={16} /> 查看译文</button>
           <button className="p-4 bg-white border border-[#e0d7c6] text-slate-400 rounded-2xl hover:text-[#c0392b] transition-all"><Share2 size={20} /></button>
        </div>
      </footer>

      <AnimatePresence>
        {activeAllusion && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setActiveAllusion(null)} className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[100]" />
            <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} className="fixed inset-x-0 bottom-0 bg-[#FDFBF7] z-[110] rounded-t-[4rem] shadow-2xl border-t border-[#e0d7c6] max-h-[85vh] overflow-y-auto p-12" >
              <div className="flex justify-between items-center mb-10">
                 <h2 className="text-4xl font-black text-[#2c3e50] italic leading-tight">{activeAllusion.text}</h2>
                 <button onClick={() => setActiveAllusion(null)} className="p-3 bg-[#f3efe6] rounded-full"><X size={24}/></button>
              </div>
              <div className="space-y-12 pb-12">
                 <section>
                   <h4 className="text-[10px] font-black uppercase text-[#c0392b] mb-4 tracking-[0.4em] italic">白话解译</h4>
                   <p className="text-2xl text-slate-600 leading-relaxed font-bold italic">“{activeAllusion.meaning}”</p>
                 </section>
                 <section className="bg-white p-10 rounded-[3rem] border border-[#e0d7c6] shadow-inner">
                    <h4 className="text-xs font-black text-slate-800 mb-6 flex items-center gap-2"><Sparkles size={14} className="text-[#c0392b]"/> 典故: {activeAllusion.allusion.title}</h4>
                    <p className="text-base text-slate-500 leading-relaxed italic font-medium">{activeAllusion.allusion.content}</p>
                 </section>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;

