import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, BookOpen, Languages, ScrollText, 
  ChevronRight, Share2, Sparkles, Database, RefreshCw, 
  Info, History, BookCopy, FileText, SearchCode, Quote
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_FULL_DATA, SanZiJingVerse, CharacterEtymology } from '../lib/sanzijingData';
import sql from '../lib/neon';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>(SAN_ZI_JING_FULL_DATA);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [activeTab, setActiveTab] = useState<'interpretation' | 'allusion' | 'philology' | 'english'>('interpretation');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedChar, setSelectedChar] = useState<CharacterEtymology | null>(null);

  const isComponentMounted = useRef(true);
  const pendingCharIdx = useRef(-1);
  const scrollRef = useRef<HTMLDivElement>(null);
  const currentVerseRef = useRef<HTMLDivElement>(null);
  const animationFrameRef = useRef<number | null>(null);

  // --- 数据库同步 (极致详尽版) ---
  const syncDatabase = useCallback(async (force = false) => {
    if (!sql) return;
    setIsLoading(true);
    try {
      await sql`
        CREATE TABLE IF NOT EXISTS sanzijing_detailed (
          id INT PRIMARY KEY,
          verse_index INT,
          chapter_name TEXT,
          text TEXT,
          chars TEXT[],
          pinyin TEXT[],
          translation_vernacular TEXT,
          translation_english TEXT,
          interpretation_deep TEXT,
          allusion JSONB,
          etymology JSONB,
          tags TEXT[]
        )
      `;

      const result = await sql`SELECT count(*) FROM sanzijing_detailed`;
      const count = parseInt(result[0].count);

      if (count === 0 || force) {
        if (force) await sql`DELETE FROM sanzijing_detailed`;
        for (const v of SAN_ZI_JING_FULL_DATA) {
          await sql`
            INSERT INTO sanzijing_detailed (
              id, verse_index, chapter_name, text, chars, pinyin, 
              translation_vernacular, translation_english, interpretation_deep, allusion, etymology, tags
            ) VALUES (
              ${v.id}, ${v.verse_index}, ${v.chapter_name}, ${v.text}, ${v.chars}, ${v.pinyin},
              ${v.translation_vernacular}, ${v.translation_english}, ${v.interpretation_deep}, 
              ${JSON.stringify(v.allusion)}, ${JSON.stringify(v.etymology)}, ${v.tags}
            ) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text
          `;
        }
      }

      const cloudData = await sql`SELECT * FROM sanzijing_detailed ORDER BY verse_index ASC`;
      setVerses(cloudData.map(d => ({
        ...d,
        allusion: typeof d.allusion === 'string' ? JSON.parse(d.allusion) : d.allusion,
        etymology: typeof d.etymology === 'string' ? JSON.parse(d.etymology) : d.etymology
      })));
    } catch (e) {
      console.error("Sync Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    syncDatabase();
    return () => {
      isComponentMounted.current = false;
      window.speechSynthesis.cancel();
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [syncDatabase]);

  // --- 高性能 UI 同步 ---
  const syncUI = useCallback(() => {
    if (pendingCharIdx.current !== currentCharIdx) setCurrentCharIdx(pendingCharIdx.current);
    if (isPlaying && isComponentMounted.current) animationFrameRef.current = requestAnimationFrame(syncUI);
  }, [currentCharIdx, isPlaying]);

  useEffect(() => {
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(syncUI);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
  }, [isPlaying, syncUI]);

  const playVerse = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].text);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.85;
    utterance.onboundary = (e) => {
      if (!isComponentMounted.current) return;
      const textBefore = verses[idx].text.substring(0, e.charIndex);
      pendingCharIdx.current = textBefore.replace(/[^\u4e00-\u9fa5]/g, '').length;
    };
    utterance.onend = () => {
      pendingCharIdx.current = -1;
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => isComponentMounted.current && isPlaying && setCurrentVerseIdx(idx + 1), 600);
      } else setIsPlaying(false);
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerse(currentVerseIdx);
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [currentVerseIdx, isPlaying, playVerse]);

  const activeVerse = verses[currentVerseIdx];

  return (
    <div className="fixed inset-0 z-50 bg-[#FDFBF7] flex flex-col font-serif overflow-hidden select-none">
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      <header className="h-16 md:h-20 bg-white/90 backdrop-blur-xl border-b border-[#e0d7c6] flex items-center justify-between px-6 md:px-10 z-20 shrink-0">
        <div className="flex items-center gap-4">
           <div className="w-10 h-10 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg"><ScrollText size={20}/></div>
           <div>
             <h1 className="text-base md:text-xl font-black text-[#2c3e50] tracking-tight">三字经全息研习控制台</h1>
             <p className="text-[8px] md:text-[9px] text-slate-400 font-bold uppercase tracking-[0.3em]">Holographic Classics Study / ID: 0x{activeVerse?.id}</p>
