import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, Languages, ScrollText, 
  ChevronRight, Sparkles, Database, RefreshCw, 
  History, BookCopy, FileText, SearchCode, Quote,
  GraduationCap, Hash, Library, MessageSquareText,
  Shapes, BookMarked, Layers, ArrowRightLeft, Mic2,
  // Fix: Add missing icons Loader2 and Target
  Loader2, Target
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCharDetail, setSelectedCharDetail] = useState<CharAnalysis | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentVerseRef = useRef<HTMLDivElement>(null);

  // --- 数据抓取 ---
  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Database Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // --- Gemini AI 现代解经 ---
  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    try {
      // Fix: Always use the direct environment variable process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位精通国学的现代教育家。请针对《三字经》中的这段经文：“${verse.content_raw}”，写一段150字左右的现代生活启示。要求：言辞优美，充满智慧，能够引起现代人的共鸣，并给出一个具体的践行建议。`,
      });
      // Fix: Access .text property directly from response
      setAiInsight(response.text || '智慧链接中断，请重试。');
    } catch (e) {
      setAiInsight('AI 思考中遇到了迷雾...');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  // --- 语音同步 ---
  const playVerse = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => isPlaying && setCurrentIdx(idx + 1), 600);
      } else setIsPlaying(false);
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerse(currentIdx);
    currentVerseRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
