              <span className="text-[8px] text-[#c0392b] font-black bg-[#c0392b]/5 px-1.5 py-0.5 rounded">第 {activeVerse?.verse_index} 节</span>
              <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{activeVerse?.chapter_name}</span>
            </div>
