             <Type size={16} />
           </button>
           <button onClick={onClose} className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all"><X size={20}/></button>
        </div>
      </header>

      {/* 主交互区 - 解决详情看不见的问题 */}
