      {/* 顶部简洁导航 */}
      <header className="h-14 md:h-16 bg-white border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-30 shrink-0 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-[#c0392b] text-white rounded-lg flex items-center justify-center shadow-lg"><Library size={18}/></div>
