            <h1 className="text-sm md:text-lg font-black text-[#2c3e50] tracking-tight">三字经 · 全息研习</h1>
            <div className="flex items-center gap-2">
              <span className="text-[8px] text-[#c0392b] font-black bg-[#c0392b]/5 px-1.5 py-0.5 rounded">SEQUENCE_{activeVerse?.verse_index}</span>
              <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{activeVerse?.chapter_name}</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={() => setShowPinyin(!showPinyin)} className={`p-2 rounded-lg border transition-all ${showPinyin ? 'bg-[#c0392b]/5 border-[#c0392b]/20 text-[#c0392b]' : 'bg-white border-slate-200 text-slate-400'}`}>
             <Type size={16} />
           </button>
           <button onClick={onClose} className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all"><X size={20}/></button>
        </div>
      </header>

      {/* 主交互区 */}
      <main className="flex-1 flex flex-col lg:flex-row overflow-hidden relative z-10">

        {/* 左/上：经文长卷 - 大号字体，书法感 */}
        <section className="flex-1 flex flex-col min-h-0 lg:h-full overflow-hidden border-r border-[#e0d7c6] bg-white/40">
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-12 space-y-16 no-scrollbar scroll-smooth pb-40">
            {verses.map((v, i) => (
              <div 
                key={v.id} 
                ref={el => { verseRefs.current[i] = el; }}
                onClick={() => { setIsPlaying(false); setCurrentIdx(i); }}
                className={`transition-all duration-700 cursor-pointer text-center group ${currentIdx === i ? 'opacity-100 scale-110' : 'opacity-10 blur-[0.5px] hover:opacity-30'}`}
              >
                <div className="flex flex-wrap justify-center gap-x-6 md:gap-x-12 gap-y-6">
                  {v.content_chars.map((char, cIdx) => (
                    <div 
                      key={cIdx} 
                      className="flex flex-col items-center relative"
                      onClick={(e) => {
                        if (v.char_analysis && v.char_analysis[char]) {
                          e.stopPropagation();
                          setSelectedCharDetail(v.char_analysis[char]);
                          setActiveTab('lexicon');
