                      }}
                    >
                      {showPinyin && (
                        <span className={`text-[10px] md:text-sm font-mono mb-2 transition-colors ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#c0392b] font-black' : 'text-slate-300'}`}>
                          {v.content_pinyin[cIdx]}
