                        <span className={`text-6xl md:text-[8rem] font-black leading-none transition-all ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1a1a1a] drop-shadow-2xl scale-110' : 'text-slate-200 group-hover:text-slate-400'}`} style={{ fontFamily: '"Noto Serif SC", serif' }}>
