             <Type size={20} />
           </button>
           <button className="p-2 text-slate-400 hover:text-[#c0392b]"><SkipForward size={20}/></button>
        </div>
      </header>

      {/* 主画布布局 */}
      <main className="flex-1 flex flex-col lg:flex-row overflow-hidden relative z-10">

        {/* 左/上：经文纵卷 (核心) */}
        <section className="flex-1 flex flex-col min-h-0 lg:h-full border-r border-[#e0d7c6] relative overflow-hidden bg-white/30">
          <div className="absolute top-0 left-0 w-full h-8 bg-gradient-to-b from-[#FDFBF7] to-transparent z-20 pointer-events-none" />

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 md:p-16 space-y-20 no-scrollbar scroll-smooth">
            {verses.map((v, i) => (
              <div 
                key={v.id} 
                ref={el => { verseRefs.current[i] = el; }}
                onClick={() => { setIsPlaying(false); setCurrentIdx(i); speak(v.content_raw); }}
                className={`transition-all duration-700 cursor-pointer flex justify-center group ${currentIdx === i ? 'opacity-100' : 'opacity-10 blur-[0.5px] hover:opacity-30'}`}
              >
                {/* 竖向红杠装饰 */}
                <div className="flex flex-row-reverse gap-6 md:gap-12 relative py-4 px-8 border-x border-[#c0392b]/20">
                  <div className="absolute top-0 left-0 w-full h-px bg-[#c0392b]/30"></div>
                  <div className="absolute bottom-0 left-0 w-full h-px bg-[#c0392b]/30"></div>

                  {/* 分组显示，每3个字一组 */}
