                           <section>
                              <div className="flex items-center justify-between mb-4">
                                <h5 className="text-[9px] font-black text-[#c0392b] uppercase tracking-widest italic">字理演变 / Evolution</h5>
                                <button onClick={() => speak(selectedCharDetail.evolution_story)} className="p-1.5 text-white/20"><Volume2 size={14}/></button>
                              </div>
                              <p className="text-lg text-slate-400 italic leading-loose text-justify">{selectedCharDetail.evolution_story}</p>
                           </section>
                           <section>
                              <div className="flex items-center justify-between mb-4">
                                <h5 className="text-[9px] font-black text-[#c0392b] uppercase tracking-widest italic">本义详注 / Original</h5>
                                <button onClick={() => speak(selectedCharDetail.original_meaning)} className="p-1.5 text-white/20"><Volume2 size={14}/></button>
                              </div>
                              <p className="text-2xl font-bold text-slate-100 leading-relaxed">{selectedCharDetail.original_meaning}</p>
                           </section>
                        </div>
                     </div>
                   ) : (
                     <div className="py-24 text-center border-2 border-dashed border-[#e0d7c6] rounded-[3rem] opacity-40">
                        <SearchCode className="mx-auto text-[#c0392b] mb-6" size={60} />
                        <p className="text-xs text-slate-400 font-black uppercase tracking-[0.4em]">点击左侧经文中的汉字，开启字理显微镜</p>
                     </div>
                   )}
                </motion.div>
              )}

              {activeTab === 'ai' && (
                <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-10">
                   <div className="p-10 bg-emerald-50/50 border border-emerald-100 rounded-[3.5rem] relative overflow-hidden shadow-sm">
                      <div className="absolute top-0 right-0 p-8 opacity-[0.03] text-emerald-600"><Sparkles size={240}/></div>
                      <div className="flex items-center justify-between mb-10">
                        <div className="flex items-center gap-4 text-emerald-600">
                          <Mic2 size={24} />
                          <h4 className="text-[10px] font-black uppercase tracking-[0.5em] italic">AI 老师的悄悄话</h4>
                        </div>
                        {!isAiLoading && aiInsight && (
                          <button onClick={() => speak(aiInsight, 1.0)} className="p-3 bg-white text-emerald-600 rounded-2xl shadow-sm">
                            <Volume2 size={24} />
                          </button>
                        )}
                      </div>

                      {isAiLoading ? (
                        <div className="py-20 flex flex-col items-center gap-6">
                           <Loader2 className="w-12 h-12 text-emerald-500 animate-spin" />
                           <p className="text-[10px] text-emerald-400 font-black uppercase tracking-[0.3em]">AI 老师正在认真思考...</p>
                        </div>
                      ) : (
                        <div className="animate-in fade-in duration-1000">
                           <p className="text-3xl font-bold text-emerald-900 leading-snug italic mb-12">“{aiInsight}”</p>
                           <div className="bg-emerald-900 text-white p-8 rounded-3xl flex items-center gap-6 shadow-2xl">
                              <Target size={32} className="text-emerald-300 shrink-0" />
                              <p className="text-sm font-medium leading-relaxed opacity-90 italic">这是专门为你准备的今日智慧小贴士，记得在生活中尝试一下哦！</p>
                           </div>
                        </div>
                      )}
                   </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </aside>
      </main>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@700;900&display=swap');

        .arrow-down {
           width: 0; 
           height: 0; 
           border-left: 10px solid transparent;
           border-right: 10px solid transparent;
           border-top: 10px solid #c0392b;
        }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;
